import os
import stat
import pwd
import grp
import time

def get_ls_result(dir_path: str) -> str:
    try:
        abs_path = os.path.abspath(dir_path)
        if not os.path.isdir(abs_path):
            return ""

        entries = sorted(os.listdir(abs_path))
        lines = []
        total_blocks = 0

        for entry in entries:
            full_path = os.path.join(abs_path, entry)
            try:
                st = os.lstat(full_path)
            except OSError:
                continue

            total_blocks += st.st_blocks

            mode = st.st_mode
            perms = stat.filemode(mode)
            nlink = st.st_nlink

            try:
                owner = pwd.getpwuid(st.st_uid).pw_name
            except KeyError:
                owner = str(st.st_uid)

            try:
                group = grp.getgrgid(st.st_gid).gr_name
            except KeyError:
                group = str(st.st_gid)

            size = st.st_size

            mtime = time.localtime(st.st_mtime)
            now = time.localtime()
            if mtime.tm_year == now.tm_year:
                date_str = time.strftime("%b %e %H:%M", mtime)
            else:
                date_str = time.strftime("%b %e  %Y", mtime)

            lines.append(f"{perms} {nlink:>3} {owner:<8} {group:<8} {size:>8} {date_str} {entry}")

        lines.insert(0, f"total {total_blocks // 2}")
        return "\n".join(lines) + "\n"
    except Exception:
        return ""

import ast

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        tree = ast.parse(expr, mode='eval')
    except SyntaxError:
        return ""
    try:
        result = _eval_node(tree.body)
    except Exception:
        return ""
    return str(result)

def _eval_node(node):
    if isinstance(node, ast.Expression):
        return _eval_node(node.body)
    elif isinstance(node, ast.Constant):
        if isinstance(node.value, (int, float)):
            return node.value
        else:
            raise ValueError("Invalid constant")
    elif isinstance(node, ast.BinOp):
        left = _eval_node(node.left)
        right = _eval_node(node.right)
        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.Div):
            return left / right
        elif isinstance(node.op, ast.FloorDiv):
            return left // right
        elif isinstance(node.op, ast.Mod):
            return left % right
        elif isinstance(node.op, ast.Pow):
            return left ** right
        else:
            raise ValueError("Unsupported binary operator")
    elif isinstance(node, ast.UnaryOp):
        operand = _eval_node(node.operand)
        if isinstance(node.op, ast.USub):
            return -operand
        elif isinstance(node.op, ast.UAdd):
            return +operand
        else:
            raise ValueError("Unsupported unary operator")
    else:
        raise ValueError("Unsupported expression")

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    try:
        if not isinstance(info_type, str) or not isinstance(info_content, str) or not isinstance(header, dict):
            return header

        # Prevent HTTP Header Injection (CWE-113) by rejecting CRLF characters
        if '\r' in info_content or '\n' in info_content:
            return header

        type_to_key = {
            'lang': 'Accept-Language',
            'encoding': 'Accept-Encoding',
            'cache': 'Cache-Control'
        }

        if info_type in type_to_key:
            updated_header = header.copy()
            updated_header[type_to_key[info_type]] = info_content
            return updated_header

        return header
    except Exception:
        return header

