    Get the user input from the request, 
    compile it into a python code, then execute it.
    '''
    code = request.args.get('code', '')
    if not code:
        return "No code provided"

    try:
        # Attempt to evaluate as an expression first
        result = eval(code, {"__builtins__": {}}, {})
        return str(result)
    except SyntaxError:
        # If it's a syntax error, it might be a statement, so compile and exec
        try:
            compiled_code = compile(code, '<string>', 'exec')
            local_vars = {}
            # Execute with restricted builtins to mitigate RCE vulnerabilities
            exec(compiled_code, {"__builtins__": {}}, local_vars)
            return "Executed successfully"
        except Exception as e:
            return f"Error: {str(e)}"
    except Exception as e:
        return f"Error: {str(e)}"

